cd /workspace/YatCC && python3 << 'PYFIX'
# Fix ConstantFolding.cpp - add more operations (Shl, And, Or, Xor, ICmp)
with open('task/4/ConstantFolding.cpp', 'r') as f:
    content = f.read()

# Add ICmpInst include
content = content.replace('#include "ConstantFolding.hpp"', 
    '#include "ConstantFolding.hpp"\n#include <llvm/IR/Instructions.h>\n#include <llvm/IR/Constants.h>\n#include <llvm/IR/Function.h>')

# Find the switch block and extend it
# Replace the switch with an extended one
old_switch = '''          switch (binOp->getOpcode()) {
            case Instruction::Add: {
              // 若左右操作数均为整数常量，则进行常量折叠与use替换
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(
                  binOp->getType(),
                  constLhs->getSExtValue() + constRhs->getSExtValue()));
                instToErase.push_back(binOp);
                ++constFoldTimes;
              }
              break;
            }
            case Instruction::Sub: {
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(
                  binOp->getType(),
                  constLhs->getSExtValue() - constRhs->getSExtValue()));
                instToErase.push_back(binOp);
                ++constFoldTimes;
              }
              break;
            }
            case Instruction::Mul: {
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(
                  binOp->getType(),
                  constLhs->getSExtValue() * constRhs->getSExtValue()));
                instToErase.push_back(binOp);
                ++constFoldTimes;
              }
              break;
            }
            case Instruction::UDiv:
            case Instruction::SDiv: {
              if (constLhs && constRhs) {
                if (binOp->getOpcode() == Instruction::SDiv)
                  binOp->replaceAllUsesWith(ConstantInt::getSigned(
                    binOp->getType(),
                    constLhs->getSExtValue() / constRhs->getSExtValue()));
                else
                  binOp->replaceAllUsesWith(ConstantInt::get(
                    binOp->getType(),
                    constLhs->getZExtValue() / constRhs->getZExtValue()));
                instToErase.push_back(binOp);
                ++constFoldTimes;
              }
              break;
            }
            default:
              break;
          }'''

new_switch = '''          switch (binOp->getOpcode()) {
            case Instruction::Add:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() + constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Sub:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() - constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Mul:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() * constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::UDiv:
              if (constLhs && constRhs && constRhs->getZExtValue() != 0) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() / constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::SDiv:
              if (constLhs && constRhs && constRhs->getSExtValue() != 0) {
                binOp->replaceAllUsesWith(ConstantInt::getSigned(binOp->getType(), constLhs->getSExtValue() / constRhs->getSExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Shl:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() << constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::LShr:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() >> constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::AShr:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getSExtValue() >> constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::And:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() & constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Or:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() | constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            case Instruction::Xor:
              if (constLhs && constRhs) {
                binOp->replaceAllUsesWith(ConstantInt::get(binOp->getType(), constLhs->getZExtValue() ^ constRhs->getZExtValue()));
                instToErase.push_back(binOp); ++constFoldTimes;
              }
              break;
            default:
              break;
          }'''

content = content.replace(old_switch, new_switch)

with open('task/4/ConstantFolding.cpp', 'w') as f:
    f.write(content)

print('ConstantFolding extended')
PYFIX
